import{_ as a,o as t,c as o,a2 as n}from"./chunks/framework.IwO0Hdn_.js";const m=JSON.parse('{"title":"[INTEGRATION] F-01.3 — Actualización en Tiempo Real via SSE","description":"","frontmatter":{},"headers":[],"relativePath":"backlog/F-01.3_sse_tiempo_real.md","filePath":"backlog/F-01.3_sse_tiempo_real.md","lastUpdated":null}'),r={name:"backlog/F-01.3_sse_tiempo_real.md"};function i(s,e,d,c,l,p){return t(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="integration-f-01-3-—-actualizacion-en-tiempo-real-via-sse" tabindex="-1">[INTEGRATION] F-01.3 — Actualización en Tiempo Real via SSE <a class="header-anchor" href="#integration-f-01-3-—-actualizacion-en-tiempo-real-via-sse" aria-label="Permalink to &quot;[INTEGRATION] F-01.3 — Actualización en Tiempo Real via SSE&quot;">​</a></h1><p><strong>Épica:</strong> EPIC-01 — Dashboard Principal (Vista en Tiempo Real)</p><h2 id="🏷️-categoria" tabindex="-1">🏷️ Categoría <a class="header-anchor" href="#🏷️-categoria" aria-label="Permalink to &quot;🏷️ Categoría&quot;">​</a></h2><p><strong>Categoría:</strong> <code>Integration</code><strong>Secundaria:</strong> <code>UI / Presentation</code><strong>Impacta en:</strong> Equipo Fullstack (Livewire + Laravel)</p><h2 id="📦-dependencias" tabindex="-1">📦 Dependencias <a class="header-anchor" href="#📦-dependencias" aria-label="Permalink to &quot;📦 Dependencias&quot;">​</a></h2><blockquote><p>Backlogs que deben estar <strong>completados</strong> antes de implementar esta feature.</p></blockquote><table tabindex="0"><thead><tr><th>Backlog</th><th>Motivo</th></tr></thead><tbody><tr><td><a href="./F-01.1_dashboard_cards_tipo.html">F-01.1</a></td><td>Componente <code>DashboardCards</code> con método <code>refreshCounts</code> para recibir el evento</td></tr><tr><td><a href="./F-01.2_dashboard_card_todos.html">F-01.2</a></td><td>Card &#39;Todos&#39; incluida en el componente que debe actualizarse</td></tr><tr><td><a href="./F-05.2_endpoint_sse.html">F-05.2</a></td><td>Endpoint <code>GET /sse/logs</code> implementado y emitiendo eventos SSE</td></tr></tbody></table><p><strong>Prioridad:</strong> <code>Must</code></p><hr><p><strong>Descripción:</strong> Como administrador del sistema Quiero que los contadores del dashboard se actualicen automáticamente sin recargar la página Para ver el estado real del sistema en todo momento sin intervención manual</p><p><strong>Criterios de Aceptación (Checklist):</strong></p><ul><li>[ ] <strong>Escenario 1 (Happy Path):</strong> Dado que n8n inserta un nuevo log Critical en Postgres, cuando han pasado menos de 2 segundos, entonces el contador de la card &quot;Critical&quot; del dashboard se incrementa automáticamente.</li><li>[ ] <strong>Escenario 2 (Reconexión):</strong> Dado que la conexión SSE se pierde (red inestable), cuando el frontend detecta el corte, entonces intenta reconectar automáticamente con backoff exponencial.</li><li>[ ] <strong>Escenario 3 (Seguridad):</strong> Dado que un usuario no autenticado intenta conectarse al endpoint SSE, cuando realiza la petición, entonces recibe un 401 Unauthorized y no recibe datos.</li><li>[ ] <strong>Requisito Técnico:</strong> Implementar via <code>StreamedResponse</code> de Laravel 12. El servidor escucha <code>pg_notify</code> (LISTEN/NOTIFY de PostgreSQL) para minimizar latencia. El endpoint SSE requiere sesión activa (middleware <code>auth</code>) antes de emitir (STRIDE I-API-01). El cliente conecta via <code>EventSource</code> JS nativo; Alpine.js despacha <code>$wire.dispatch(&#39;refreshCounts&#39;)</code> al recibir el evento.</li></ul>',12)])])}const g=a(r,[["render",i]]);export{m as __pageData,g as default};
